import React, { useState } from "react";
import axios from "axios";
import { WiHumidity, WiStrongWind, WiCloudy, WiDaySunny } from "react-icons/wi";
import { motion } from "framer-motion";

const WeatherUpdate = () => {
    const [city, setCity] = useState("");
    const [weather, setWeather] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchWeather = async () => {
        if (!city) {
            setError("Please enter a city name.");
            return;
        }
        setLoading(true);
        setError("");
        try {
            const response = await axios.get(`http://localhost:5000/api/weather/getWeather?city=${city}`);
            setWeather(response.data);
        } catch (err) {
            setError("Failed to fetch weather data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="flex flex-col items-center p-4 bg-gray-100 min-h-screen">
            <div className="w-full max-w-3xl bg-white shadow-lg rounded-xl p-6">
                <h2 className="text-2xl font-semibold text-gray-800 mb-4">🌤 Weather Update</h2>
                <div className="flex space-x-2 mb-4">
                    <input
                        type="text"
                        placeholder="Enter city name"
                        value={city}
                        onChange={(e) => setCity(e.target.value)}
                        className="flex-1 p-2 border rounded-lg"
                    />
                    <motion.button
                        onClick={fetchWeather}
                        className="bg-blue-500 text-white px-4 py-2 rounded-lg"
                        whileTap={{ scale: 0.95 }}
                    >
                        Get Weather
                    </motion.button>
                </div>

                {loading && <p className="text-center text-gray-600">Loading...</p>}
                {error && <p className="text-center text-red-500">{error}</p>}

                {weather && (
                    <div className="bg-blue-50 p-4 rounded-lg shadow-md">
                        <h3 className="text-xl font-bold text-gray-900">{weather.location}</h3>
                        <div className="text-4xl font-semibold mt-2">{weather.temperature}°C</div>
                        <p className="text-gray-600">{weather.weather}</p>
                        <div className="flex justify-between items-center mt-4">
                            <p className="flex items-center"><WiHumidity className="text-2xl mr-1" /> {weather.humidity}%</p>
                            <p className="flex items-center"><WiStrongWind className="text-2xl mr-1" /> {weather.wind_speed} kph</p>
                        </div>
                    </div>
                )}
            </div>

            {weather?.forecast && (
                <div className="w-full max-w-3xl bg-white shadow-lg rounded-xl p-6 mt-6">
                    <h3 className="text-xl font-semibold text-gray-800 mb-4">7-Day Forecast</h3>
                    <div className="space-y-2">
                        {weather.forecast.map((day, index) => (
                            <div key={index} className="p-3 bg-blue-100 rounded-lg shadow">
                                <p className="font-medium">{day.date}</p>
                                <p className="flex items-center">
                                    {day.condition === "Sunny" ? <WiDaySunny className="text-yellow-500 text-2xl mr-2" /> : <WiCloudy className="text-gray-500 text-2xl mr-2" />}
                                    {day.condition}
                                </p>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

export default WeatherUpdate;
